errors.codeBlock:
// BEFORE (wrong)
public void () { }

// AFTER (correct)
public void MyMethod() { }

// BEFORE (wrong)
int x = 5

// AFTER (correct)
int x = 5;

// BEFORE (wrong)
string s = "hello
world";

// AFTER (correct)
string s = "hello\nworld";
// or
string s = @"hello
world";
// or (C# 11+)
string s = """
    hello
    world
    """;

// BEFORE (wrong)
char c = 'ab';

// AFTER (correct)
string s = "ab";
// or
char c = 'a';

// BEFORE (wrong)
class MyClass
{
    Console.WriteLine("hello"); // statements can't be here
}

// AFTER (correct)
class MyClass
{
    public void DoSomething()
    {
        Console.WriteLine("hello");
    }
}

// BEFORE (wrong)
namespace MyApp
{
    void DoSomething() { }
}

// AFTER (correct)
namespace MyApp
{
    public class Program
    {
        void DoSomething() { }
    }
}

// BEFORE (wrong)
List<string> items = new List<string>();
// CS0246: The type or namespace name 'List<>' could not be found

// AFTER (correct)
using System.Collections.Generic;

List<string> items = new List<string>();

// BEFORE (wrong)
using Microsoft.AspNetCore.Mvc;
// CS0234: 'ApiController' does not exist in 'Microsoft.AspNetCore.Mvc'

// FIX: Install the package
// dotnet add package Microsoft.AspNetCore.Mvc.Core

// BEFORE (wrong)
Console.WriteLine(Max(1, 2));
// CS0103: The name 'Max' does not exist in the current context

// AFTER (correct)
using static System.Math;
Console.WriteLine(Max(1, 2));

// BEFORE (wrong)
int count = MyClass.Count; // CS0117 if Count is instance member

// AFTER (correct)
var obj = new MyClass();
int count = obj.Count;

// BEFORE (wrong)
public class MyClass
{
    public int Value = 10;
    public static void Print()
    {
        Console.WriteLine(Value); // CS0120
    }
}

// AFTER (correct — option 1: make member static)
public class MyClass
{
    public static int Value = 10;
    public static void Print()
    {
        Console.WriteLine(Value);
    }
}

// AFTER (correct — option 2: use instance)
public class MyClass
{
    public int Value = 10;
    public static void Print()
    {
        var obj = new MyClass();
        Console.WriteLine(obj.Value);
    }
}

// BEFORE (wrong)
public class Base
{
    private int _value;
}
public class Other
{
    void Do() { var b = new Base(); int v = b._value; } // CS0122
}

// AFTER (correct)
public class Base
{
    public int Value { get; private set; }
}

// BEFORE (wrong)
var list = new List<int> { 1, 2, 3 };
var first = list.FirstItem(); // CS1061

// AFTER (correct — extension method)
using System.Linq;
var list = new List<int> { 1, 2, 3 };
var first = list.First();

// BEFORE (wrong)
string s = "5";
if (s == 5) { } // CS0019: cannot apply == to string and int

// AFTER (correct)
if (int.Parse(s) == 5) { }
// or
if (s == "5") { }

// BEFORE (wrong)
string name = user.GetName; // CS0428 — missing ()

// AFTER (correct)
string name = user.GetName();

// BEFORE (wrong)
var obj = new MyClass();
obj.StaticMethod(); // CS0176

// AFTER (correct)
MyClass.StaticMethod();

// BEFORE (wrong)
int x = 3.14; // CS0029: cannot convert double to int

// AFTER (correct)
int x = (int)3.14;
// or
double x = 3.14;

