errors.prescription:
1. Add a null check: if (obj != null) { obj.Method(); }
2. Use the null-conditional operator: obj?.Method();
3. Use pattern matching: if (obj is Type t) { t.Method(); }
4. Ensure the variable is assigned a non-null value before use.
5. Use the '!' operator only if you are certain it cannot be null.

errors.codeBlock:
// BEFORE (warning)
string upper = name.ToUpper(); // CS8602 if name could be null

// AFTER (correct — null conditional)
string? upper = name?.ToUpper();

// AFTER (correct — null check)
if (name is not null)
{
    string upper = name.ToUpper();
}

// BEFORE (warning)
public string FindName(int id)
{
    return _names.GetValueOrDefault(id); // may return null, CS8603
}

// AFTER (correct — nullable return)
public string? FindName(int id)
{
    return _names.GetValueOrDefault(id);
}

// AFTER (correct — guarantee non-null)
public string FindName(int id)
{
    return _names.GetValueOrDefault(id) ?? throw new KeyNotFoundException();
}

// BEFORE (warning)
string? name = GetName();
Process(name); // CS8604: name might be null

// AFTER (correct)
string? name = GetName();
if (name is not null)
{
    Process(name);
}

// AFTER (correct — null coalescing)
Process(name ?? "default");

// BEFORE (warning)
object? obj = GetValue();
int value = (int)obj; // CS8605

// AFTER (correct)
if (obj is int value)
{
    // use value
}

errors.prescription:
1. Initialize the member in the constructor.
2. Initialize with a default value at declaration: public string Name { get; set; } = string.Empty;
3. Make the member nullable: public string? Name { get; set; }
4. Use the 'required' keyword (C# 11+): public required string Name { get; set; }
5. Suppress with '= null!' if initialization happens elsewhere (e.g., EF Core, DI).

errors.codeBlock:
// BEFORE (warning)
public class User
{
    public string Name { get; set; } // CS8618
    public string Email { get; set; } // CS8618
}

// AFTER (correct — initialize in constructor)
public class User
{
    public string Name { get; set; }
    public string Email { get; set; }
    public User(string name, string email)
    {
        Name = name;
        Email = email;
    }
}

// AFTER (correct — default values)
public class User
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

// AFTER (correct — required keyword, C# 11+)
public class User
{
    public required string Name { get; set; }
    public required string Email { get; set; }
}

// BEFORE (warning)
string name = null; // CS8625

// AFTER (correct)
string? name = null;
// or
string name = string.Empty;

// BEFORE (wrong)
public interface IService
{
    Task<Result> ProcessAsync(Request request);
}

public class MyService : IService
{
    // CS0535: Missing ProcessAsync
}

// AFTER (correct)
public class MyService : IService
{
    public async Task<Result> ProcessAsync(Request request)
    {
        // implementation
        return new Result();
    }
}

// BEFORE (wrong)
public abstract class BaseHandler
{
    public abstract void Handle(Request request);
}

public class MyHandler : BaseHandler
{
    // CS0534: Missing Handle override
}

// AFTER (correct)
public class MyHandler : BaseHandler
{
    public override void Handle(Request request)
    {
        // implementation
    }
}

// BEFORE (wrong — parameter mismatch)
public class Base
{
    public virtual void Process(string input) { }
}
public class Derived : Base
{
    public override void Process(int input) { } // CS0115 — wrong parameter type
}

// AFTER (correct)
public class Derived : Base
{
    public override void Process(string input) { }
}

// BEFORE (wrong)
var user = new User("Alice"); // CS7036: missing 'email' parameter

// AFTER (correct)
var user = new User("Alice", "alice@example.com");

// Or make the parameter optional in the constructor:
public User(string name, string email = "") { }

// BEFORE (wrong)
public int GetValue(bool flag)
{
    if (flag)
        return 1;
    // CS0161: missing return for else branch
}

// AFTER (correct)
