{
    partial void OnModelCreating(ModelBuilder builder) { /* generated */ }
}

// GlobalUsings.cs
global using System.Text.Json;
global using Microsoft.Extensions.Logging;

// Now ALL .cs files in the project can use JsonSerializer and ILogger without a using directive

// Without using System.Linq:
var list = new List<int> { 1, 2, 3 };
var first = list.First(); // CS1061 — First is an extension method from System.Linq

// Fix: add
using System.Linq;

// NOT ALLOWED:
// ProjectA.csproj references ProjectB.csproj
// ProjectB.csproj references ProjectA.csproj
//
// Solution: Create ProjectShared.csproj with interfaces
// ProjectA -> ProjectShared
// ProjectB -> ProjectShared

// File with nullable enabled
#nullable enable
public string? GetName() => null; // valid

// File with nullable disabled
#nullable disable
string name = GetName(); // no warning even though GetName returns string?

#if NET8_0_OR_GREATER
public required string Name { get; set; }
#else
public string Name { get; set; } = string.Empty;
#endif
